#include <iostream>
using namespace std;
int main(){
  int arr[]={1,3,5,7,9}, key=7, l=0, h=4;
  while(l<=h){ int mid=(l+h)/2;
    if(arr[mid]==key){ cout<<"Found"; return 0; }
    else if(arr[mid]<key) l=mid+1;
    else h=mid-1;
  }
  cout<<"Not Found";
}

