#include <iostream>
using namespace std;
int max3(int a, int b, int c) {
  int m = a;
  if (b > m) m = b;
  if (c > m) m = c;
  return m;
}
int main() {
  int a, b, c;
  cout << "Enter three integers: ";
  cin >> a >> b >> c;
  cout << "Maximum = " << max3(a, b, c);
  return 0;
}

#include <iostream>
#include <string>
using namespace std;
int main() {
  string s;
  cout << "Enter a string: ";
  getline(cin, s);
  if (s.size() == 0) getline(cin, s); // handles leftover newline in some environments
  string rev = "";
  for (int i = s.size() - 1; i >= 0; --i) {
    rev += s[i];
  }
  cout << "Reversed: " << rev;
  return 0;
}

#include <iostream>
using namespace std;
int main() {
  int n;
  cout << "Enter size of array: ";
  cin >> n;
  int arr[100];
  cout << "Enter " << n << " elements: ";
  for (int i = 0; i < n; ++i) cin >> arr[i];
  int key;
  cout << "Enter element to search: ";
  cin >> key;
  int pos = -1;
  for (int i = 0; i < n; ++i) {
    if (arr[i] == key) {
      pos = i;
      break;
    }
  }
  if (pos == -1) cout << "Not found";
  else cout << "Found at index " << pos;
  return 0;
}

